import { extractAcceptanceCriteria } from './src/lib/ac-parser.ts';
import { StateManager } from './src/lib/workflow/state-manager.ts';

const issueBody = \`## Context

During #369 (Aider) merge, we discovered that main already had 14 build errors and 5 test failures from #372 (MCP server). The \\\`/merger\\\` skill ran a post-merge smoketest but had no way to distinguish \"pre-existing failures\" from \"regressions introduced by this merge.\"

This means a PR that breaks the build could be merged as long as the developer says \"those failures are pre-existing.\" The merger has no automated check.

## Problem

\\\`/merger\\\` currently:
1. Merges the PR
2. Runs build + tests on main after merge
3. Reports results

It does NOT:
- Run build + tests on main **before** merge (baseline)
- Compare before/after to detect regressions
- Block merge when new failures are introduced

## Goal

Add a baseline comparison step to \\\`/merger\\\` so it refuses to merge PRs that introduce new build errors or test failures.

## Acceptance Criteria

- [ ] Before merging, \\\`/merger\\\` captures baseline metrics on main: build error count, test pass/fail counts
- [ ] After merging, \\\`/merger\\\` compares post-merge metrics against baseline
- [ ] If post-merge has MORE build errors or test failures than baseline → report as regression and warn
- [ ] Regression report clearly shows which errors/failures are new vs pre-existing
- [ ] \\\`--force\\\` flag allows overriding the regression gate (with explicit acknowledgment)
- [ ] Baseline metrics are cached for the session (don't re-run if merging multiple issues)\`;

const ac = extractAcceptanceCriteria(issueBody);
console.log('Extracted AC:', JSON.stringify(ac, null, 2));

if (ac.items.length > 0) {
  const manager = new StateManager();
  (async () => {
    await manager.updateAcceptanceCriteria(397, ac);
    console.log('AC stored in state for issue #397');
  })();
}
" 2>&1

