  1→#!/usr/bin/env npx tsx
  2→/**
  3→ * CLI helper for workflow state updates
  4→ *
  5→ * Skills invoke this script to update .sequant/state.json when running standalone.
  6→ * When SEQUANT_ORCHESTRATOR is set, the script exits early (orchestrator handles state).
  7→ *
  8→ * Usage:
  9→ *   npx tsx scripts/state/update.ts start <issue> <phase>
 10→ *   npx tsx scripts/state/update.ts complete <issue> <phase>
 11→ *   npx tsx scripts/state/update.ts fail <issue> <phase> "<error>"
 12→ *   npx tsx scripts/state/update.ts skip <issue> <phase>
 13→ *   npx tsx scripts/state/update.ts init <issue> "<title>"
 14→ *   npx tsx scripts/state/update.ts status <issue> <status>
 15→ *   npx tsx scripts/state/update.ts iteration <issue> <iteration>
 16→ *   npx tsx scripts/state/update.ts merged <issue>
 17→ *   npx tsx scripts/state/update.ts pr <issue> <pr-number> <pr-url>
 18→ *   npx tsx scripts/state/update.ts ac <issue> <ac-id> <status> "<notes>"
 19→ *   npx tsx scripts/state/update.ts init-ac <issue> <ac-ids-csv> "<descriptions-csv>"
 20→ *
 21→ * Examples:
 22→ *   npx tsx scripts/state/update.ts start 119 exec
 23→ *   npx tsx scripts/state/update.ts complete 119 exec
 24→ *   npx tsx scripts/state/update.ts fail 119 qa "Tests failed"
 25→ *   npx tsx scripts/state/update.ts init 119 "Add feature X"
 26→ *   npx tsx scripts/state/update.ts status 119 ready_for_merge
 27→ *   npx tsx scripts/state/update.ts merged 119
 28→ */
 29→
 30→import { StateManager } from "../../src/lib/workflow/state-manager.js";
 31→import type {
 32→  Phase,
 33→  IssueStatus,
 34→  ACStatus,
 35→  AcceptanceCriterion,
 36→} from "../../src/lib/workflow/state-schema.js";
 37→import { createAcceptanceCriteria } from "../../src/lib/workflow/state-schema.js";
 38→
 39→// Check if running in orchestrated mode
 40→if (process.env.SEQUANT_ORCHESTRATOR) {
 41→  // Orchestrator handles state - exit silently
 42→  process.exit(0);
 43→}
 44→
 45→const [, , command, ...args] = process.argv;
 46→
 47→if (!command) {
 48→  console.error("Usage: npx tsx scripts/state/update.ts <command> <args>");
 49→  console.error("");
 50→  console.error("Commands:");
 51→  console.error("  start <issue> <phase>         - Mark phase as in_progress");
 52→  console.error("  complete <issue> <phase>      - Mark phase as completed");
 53→  console.error("  fail <issue> <phase> <error>  - Mark phase as failed");
 54→  console.error("  skip <issue> <phase>          - Mark phase as skipped");
 55→  console.error("  init <issue> <title>          - Initialize issue tracking");
 56→  console.error("  status <issue> <status>       - Update issue status");
 57→  console.error("  iteration <issue> <n>         - Update loop iteration");
 58→  console.error("  merged <issue>                - Mark issue as merged");
 59→  console.error("  pr <issue> <pr-number> <url>  - Record PR info for issue");
 60→  console.error("  ac <issue> <ac-id> <status> <notes> - Update AC status");
 61→  console.error("  init-ac <issue> <count>           - Initialize N AC items");
 62→  process.exit(1);
 63→}
 64→
 65→const manager = new StateManager({ verbose: true });
 66→
 67→async function main(): Promise<void> {
 68→  try {
 69→    switch (command) {
 70→      case "start": {
 71→        const [issueStr, phase] = args;
 72→        const issueNumber = parseInt(issueStr, 10);
 73→        if (isNaN(issueNumber) || !phase) {
 74→          console.error("Usage: start <issue> <phase>");
 75→          process.exit(1);
 76→        }
 77→        await ensureIssueExists(issueNumber);
 78→        await manager.updatePhaseStatus(
 79→          issueNumber,
 80→          phase as Phase,
 81→          "in_progress",
 82→        );
 83→        console.log(`📊 Phase '${phase}' started for issue #${issueNumber}`);
 84→        break;
 85→      }
 86→
 87→      case "complete": {
 88→        const [issueStr, phase] = args;
 89→        const issueNumber = parseInt(issueStr, 10);
 90→        if (isNaN(issueNumber) || !phase) {
 91→          console.error("Usage: complete <issue> <phase>");
 92→          process.exit(1);
 93→        }
 94→        await ensureIssueExists(issueNumber);
 95→        await manager.updatePhaseStatus(
 96→          issueNumber,
 97→          phase as Phase,
 98→          "completed",
 99→        );
100→        console.log(`📊 Phase '${phase}' completed for issue #${issueNumber}`);
101→        break;
102→      }
103→
104→      case "fail": {
105→        const [issueStr, phase, ...errorParts] = args;
106→        const issueNumber = parseInt(issueStr, 10);
107→        const error = errorParts.join(" ");
108→        if (isNaN(issueNumber) || !phase) {
109→          console.error('Usage: fail <issue> <phase> "<error>"');
110→          process.exit(1);
111→        }
112→        await ensureIssueExists(issueNumber);
113→        await manager.updatePhaseStatus(issueNumber, phase as Phase, "failed", {
114→          error: error || "Phase failed",
115→        });
116→        console.log(`📊 Phase '${phase}' failed for issue #${issueNumber}`);
117→        break;
118→      }
119→
120→      case "skip": {
121→        const [issueStr, phase] = args;
122→        const issueNumber = parseInt(issueStr, 10);
123→        if (isNaN(issueNumber) || !phase) {
124→          console.error("Usage: skip <issue> <phase>");
125→          process.exit(1);
126→        }
127→        await ensureIssueExists(issueNumber);
128→        await manager.updatePhaseStatus(issueNumber, phase as Phase, "skipped");
129→        console.log(`📊 Phase '${phase}' skipped for issue #${issueNumber}`);
130→        break;
131→      }
132→
133→      case "init": {
134→        const [issueStr, ...titleParts] = args;
135→        const issueNumber = parseInt(issueStr, 10);
136→        const title = titleParts.join(" ");
137→        if (isNaN(issueNumber) || !title) {
138→          console.error('Usage: init <issue> "<title>"');
139→          process.exit(1);
140→        }
141→        const existing = await manager.getIssueState(issueNumber);
142→        if (existing) {
143→          console.log(`📊 Issue #${issueNumber} already initialized, skipping`);
144→        } else {
145→          await manager.initializeIssue(issueNumber, title, {
146→            worktree: process.env.SEQUANT_WORKTREE,
147→          });
148→          console.log(`📊 Initialized issue #${issueNumber}: ${title}`);
149→        }
150→        break;
151→      }
152→
153→      case "status": {
154→        const [issueStr, status] = args;
155→        const issueNumber = parseInt(issueStr, 10);
156→        if (isNaN(issueNumber) || !status) {
157→          console.error("Usage: status <issue> <status>");
158→          console.error(
159→            "Valid statuses: not_started, in_progress, ready_for_merge, merged, blocked, abandoned",
160→          );
161→          process.exit(1);
162→        }
163→        await ensureIssueExists(issueNumber);
164→        await manager.updateIssueStatus(issueNumber, status as IssueStatus);
165→        console.log(`📊 Issue #${issueNumber} status updated to '${status}'`);
166→        break;
167→      }
168→
169→      case "iteration": {
170→        const [issueStr, iterStr] = args;
171→        const issueNumber = parseInt(issueStr, 10);
172→        const iteration = parseInt(iterStr, 10);
173→        if (isNaN(issueNumber) || isNaN(iteration)) {
174→          console.error("Usage: iteration <issue> <iteration>");
175→          process.exit(1);
176→        }
177→        await ensureIssueExists(issueNumber);
178→        const issueState = await manager.getIssueState(issueNumber);
179→        if (!issueState?.loop) {
180→          console.warn(
181→            `⚠️  Issue #${issueNumber} has no quality loop configured - iteration not tracked`,
182→          );
183→          break;
184→        }
185→        await manager.updateLoopIteration(issueNumber, iteration);
186→        console.log(`📊 Loop iteration ${iteration} for issue #${issueNumber}`);
187→        break;
188→      }
189→
190→      case "merged": {
191→        const [issueStr] = args;
192→        const issueNumber = parseInt(issueStr, 10);
193→        if (isNaN(issueNumber)) {
194→          console.error("Usage: merged <issue>");
195→          process.exit(1);
196→        }
197→        await ensureIssueExists(issueNumber);
198→        await manager.updateIssueStatus(issueNumber, "merged");
199→        console.log(`📊 Issue #${issueNumber} marked as merged`);
200→        break;
201→      }
202→
203→      case "pr": {
204→        const [issueStr, prNumStr, prUrl] = args;
205→        const issueNumber = parseInt(issueStr, 10);
206→        const prNumber = parseInt(prNumStr, 10);
207→        if (isNaN(issueNumber) || isNaN(prNumber) || !prUrl) {
208→          console.error("Usage: pr <issue> <pr-number> <pr-url>");
209→          process.exit(1);
210→        }
211→        // Validate URL format
212→        try {
213→          new URL(prUrl);
214→        } catch {
215→          console.error(`Invalid URL: ${prUrl}`);
216→          process.exit(1);
217→        }
218→        await ensureIssueExists(issueNumber);
219→        await manager.updatePRInfo(issueNumber, {
220→          number: prNumber,
221→          url: prUrl,
222→        });
223→        console.log(`📊 PR #${prNumber} linked to issue #${issueNumber}`);
224→        break;
225→      }
226→
227→      case "init-ac": {
228→        const [issueStr, countStr] = args;
229→        const issueNumber = parseInt(issueStr, 10);
230→        const count = parseInt(countStr, 10);
231→        if (isNaN(issueNumber) || isNaN(count) || count < 1) {
232→          console.error("Usage: init-ac <issue> <count>");
233→          console.error("Example: init-ac 250 6  # Creates AC-1 through AC-6");
234→          process.exit(1);
235→        }
236→        await ensureIssueExists(issueNumber);
237→        const items: AcceptanceCriterion[] = Array.from(
238→          { length: count },
239→          (_, i) => ({
240→            id: `AC-${i + 1}`,
241→            description: `Acceptance criterion ${i + 1}`,
242→            verificationMethod: "manual" as const,
243→            status: "pending" as ACStatus,
244→          }),
245→        );
246→        const ac = createAcceptanceCriteria(items);
247→        await manager.updateAcceptanceCriteria(issueNumber, ac);
248→        console.log(
249→          `📊 Initialized ${count} AC items for issue #${issueNumber}`,
250→        );
251→        break;
252→      }
253→
254→      case "ac": {
255→        const [issueStr, acId, status, ...notesParts] = args;
256→        const issueNumber = parseInt(issueStr, 10);
257→        const notes = notesParts.join(" ");
258→        if (isNaN(issueNumber) || !acId || !status) {
259→          console.error('Usage: ac <issue> <ac-id> <status> "<notes>"');
260→          console.error("Valid statuses: met, not_met, blocked, pending");
261→          process.exit(1);
262→        }
263→        const validStatuses = ["met", "not_met", "blocked", "pending"];
264→        if (!validStatuses.includes(status)) {
265→          console.error(`Invalid status: ${status}`);
266→          console.error("Valid statuses: met, not_met, blocked, pending");
267→          process.exit(1);
268→        }
269→        await ensureIssueExists(issueNumber);
270→        await manager.updateACStatus(
271→          issueNumber,
272→          acId,
273→          status as ACStatus,
274→          notes || undefined,
275→        );
276→        console.log(
277→          `📊 AC '${acId}' updated to '${status}' for issue #${issueNumber}`,
278→        );
279→        break;
280→      }
