208→/**
209→ * Determine which checks to run based on command options.
210→ *
211→ * --scan, --review, and --all currently return the same checks because
212→ * Phase 3 (AI briefing) is not yet implemented. When Phase 3 is added,
213→ * --review and --all will include additional AI-powered checks.
214→ * The distinction is preserved so callers can detect review mode
215→ * and show the Phase 3 stub message (see merge.ts).
216→ */
217→export function getChecksToRun(options: MergeCommandOptions): string[] {
218→  const phase1 = ["combined-branch-test", "mirroring", "overlap-detection"];
219→  const phase2 = ["residual-pattern-scan"];
220→  // Phase 3 checks will be added here when AI briefing is implemented
221→  // const phase3 = ["ai-briefing"];
222→
223→  if (options.all || options.review || options.scan) {
224→    return [...phase1, ...phase2];
225→  }
226→  // Default --check: Phase 1 only
227→  return phase1;
