230→/**
231→ * Run all merge checks and produce a report.
232→ *
233→ * @param issueNumbers - Issue numbers to check (empty = auto-detect from most recent run)
234→ * @param options - Command options controlling which checks to run
235→ * @param repoRoot - Path to the git repository root
236→ * @returns MergeReport with all findings
237→ */
238→export async function runMergeChecks(
239→  issueNumbers: number[],
240→  options: MergeCommandOptions,
241→  repoRoot: string,
242→): Promise<MergeReport> {
243→  const logDir = resolveLogDir();
244→  let runLog: RunLog | null = null;
245→
246→  // Auto-detect issues from most recent run log if none specified
247→  if (issueNumbers.length === 0) {
248→    runLog = findMostRecentLog(logDir);
249→    if (!runLog) {
250→      throw new Error(
251→        "No run logs found. Specify issue numbers or run `sequant run` first.",
252→      );
253→    }
254→    issueNumbers = runLog.issues.map((i) => i.issueNumber);
255→  } else {
256→    // Still try to load run log for metadata
257→    runLog = findMostRecentLog(logDir);
258→  }
259→
260→  // Resolve branches for each issue
261→  const branches = resolveBranches(issueNumbers, repoRoot, runLog);
262→
263→  if (branches.length === 0) {
264→    throw new Error(
265→      "No feature branches found for the specified issues. " +
266→        "Ensure branches exist (pushed to remote or in local worktrees).",
267→    );
268→  }
269→
270→  // Determine which checks to run
271→  const checksToRun = getChecksToRun(options);
272→  const checkResults: CheckResult[] = [];
273→
274→  // Phase 1: Deterministic checks
275→  if (checksToRun.includes("combined-branch-test")) {
276→    checkResults.push(runCombinedBranchTest(branches, repoRoot));
277→  }
278→
279→  if (checksToRun.includes("mirroring")) {
280→    checkResults.push(runMirroringCheck(branches, DEFAULT_MIRROR_PAIRS));
281→  }
282→
283→  if (checksToRun.includes("overlap-detection")) {
284→    checkResults.push(runOverlapDetection(branches, repoRoot));
285→  }
286→
287→  // Phase 2: Residual pattern detection
288→  if (checksToRun.includes("residual-pattern-scan")) {
289→    checkResults.push(runResidualPatternScan(branches, repoRoot));
290→  }
291→
292→  // Build report
293→  const report = buildReport(branches, checkResults, runLog?.runId);
294→
295→  // Post to GitHub if requested
296→  if (options.post) {
297→    postReportToGitHub(report);
298→  }
299→
300→  return report;
301→}
