 26→}
 27→
 28→/**
 29→ * Run a git command and return the result
 30→ */
 31→function git(
 32→  args: string[],
 33→  cwd?: string,
 34→): { ok: boolean; stdout: string; stderr: string } {
 35→  const result = spawnSync("git", args, {
 36→    cwd,
 37→    stdio: "pipe",
 38→    encoding: "utf-8",
 39→  });
 40→  return {
 41→    ok: result.status === 0,
 42→    stdout: result.stdout?.trim() ?? "",
 43→    stderr: result.stderr?.trim() ?? "",
 44→  };
 45→}
 46→
 47→/**
 48→ * Run npm command and return result
 49→ */
 50→function npm(
 51→  args: string[],
 52→  cwd?: string,
 53→): { ok: boolean; stdout: string; stderr: string } {
 54→  const result = spawnSync("npm", args, {
 55→    cwd,
 56→    stdio: "pipe",
 57→    encoding: "utf-8",
 58→    timeout: 120_000, // 2 min timeout for test/build
 59→  });
 60→  return {
 61→    ok: result.status === 0,
 62→    stdout: result.stdout?.trim() ?? "",
 63→    stderr: result.stderr?.trim() ?? "",
 64→  };
 65→}
