 67→/**
 68→ * Create temp branch, merge all feature branches, run tests and build.
 69→ *
 70→ * @param branches - Feature branches to merge
 71→ * @param repoRoot - Path to the git repository root
 72→ * @returns CheckResult with combined test findings
 73→ */
 74→export function runCombinedBranchTest(
 75→  branches: BranchInfo[],
 76→  repoRoot: string,
 77→): CheckResult {
 78→  const startTime = Date.now();
 79→  const tempBranch = `merge-check/temp-${Date.now()}`;
 80→  const branchResults: BranchCheckResult[] = [];
 81→  const batchFindings: CheckFinding[] = [];
 82→  const mergeAttempts: MergeAttempt[] = [];
 83→
 84→  // Save current branch to restore in finally block
 85→  const originalBranch = git(["rev-parse", "--abbrev-ref", "HEAD"], repoRoot);
 86→
 87→  try {
 88→    // Fetch latest from remote
 89→    git(["fetch", "origin"], repoRoot);
 90→
 91→    // Create temp branch from main
 92→    const createResult = git(
 93→      ["checkout", "-b", tempBranch, "origin/main"],
 94→      repoRoot,
 95→    );
 96→    if (!createResult.ok) {
 97→      batchFindings.push({
 98→        check: "combined-branch-test",
 99→        severity: "error",
100→        message: `Failed to create temp branch: ${createResult.stderr}`,
101→      });
102→      return buildResult(branchResults, batchFindings, startTime);
103→    }
104→
105→    // Merge each feature branch
106→    for (const branch of branches) {
107→      const mergeResult = git(
108→        ["merge", "--no-ff", "--no-edit", getBranchRef(branch)],
109→        repoRoot,
110→      );
111→
112→      if (mergeResult.ok) {
113→        mergeAttempts.push({
114→          issueNumber: branch.issueNumber,
115→          branch: branch.branch,
116→          success: true,
117→        });
118→        branchResults.push({
119→          issueNumber: branch.issueNumber,
120→          verdict: "PASS",
121→          findings: [
122→            {
123→              check: "combined-branch-test",
124→              severity: "info",
125→              message: `Branch merged cleanly into combined state`,
126→              issueNumber: branch.issueNumber,
127→            },
128→          ],
129→        });
130→      } else {
131→        // Get conflicting files
132→        const conflictResult = git(
133→          ["diff", "--name-only", "--diff-filter=U"],
134→          repoRoot,
135→        );
136→        const conflictFiles = conflictResult.stdout
137→          ? conflictResult.stdout.split("\n")
138→          : [];
139→
140→        mergeAttempts.push({
141→          issueNumber: branch.issueNumber,
142→          branch: branch.branch,
143→          success: false,
144→          conflictFiles,
145→          error: mergeResult.stderr,
146→        });
147→
148→        branchResults.push({
149→          issueNumber: branch.issueNumber,
150→          verdict: "FAIL",
151→          findings: [
152→            {
153→              check: "combined-branch-test",
154→              severity: "error",
155→              message: `Merge conflict with ${conflictFiles.length} file(s): ${conflictFiles.join(", ")}`,
156→              issueNumber: branch.issueNumber,
157→            },
158→          ],
159→        });
160→
161→        // Abort the failed merge and continue
162→        git(["merge", "--abort"], repoRoot);
163→      }
164→    }
165→
166→    // If any merges failed, skip tests but report what we have
167→    const failedMerges = mergeAttempts.filter((m) => !m.success);
168→    if (failedMerges.length > 0) {
169→      batchFindings.push({
170→        check: "combined-branch-test",
171→        severity: "error",
172→        message: `${failedMerges.length}/${branches.length} branches had merge conflicts — skipping test/build`,
173→      });
174→      return buildResult(branchResults, batchFindings, startTime);
175→    }
176→
177→    // Run npm test
178→    const testResult = npm(["test"], repoRoot);
179→    if (testResult.ok) {
180→      batchFindings.push({
181→        check: "combined-branch-test",
182→        severity: "info",
183→        message: "npm test passed on combined state",
184→      });
185→    } else {
186→      batchFindings.push({
187→        check: "combined-branch-test",
188→        severity: "error",
189→        message: `npm test failed on combined state: ${testResult.stderr.slice(0, 500)}`,
190→      });
191→    }
192→
193→    // Run npm run build
194→    const buildResult2 = npm(["run", "build"], repoRoot);
195→    if (buildResult2.ok) {
196→      batchFindings.push({
197→        check: "combined-branch-test",
198→        severity: "info",
199→        message: "npm run build passed on combined state",
200→      });
201→    } else {
202→      batchFindings.push({
203→        check: "combined-branch-test",
204→        severity: "error",
205→        message: `npm run build failed on combined state: ${buildResult2.stderr.slice(0, 500)}`,
206→      });
207→    }
208→
209→    return buildResult(branchResults, batchFindings, startTime);
210→  } finally {
211→    // Clean up: restore original branch and delete temp branch
212→    const restoreBranch = originalBranch.ok ? originalBranch.stdout : "main";
213→    git(["checkout", restoreBranch], repoRoot);
214→    git(["branch", "-D", tempBranch], repoRoot);
215→  }
216→}
217→
218→export function buildResult(
219→  branchResults: BranchCheckResult[],
220→  batchFindings: CheckFinding[],
221→  startTime: number,
222→): CheckResult {
223→  const hasErrors = batchFindings.some((f) => f.severity === "error");
224→  return {
225→    name: "combined-branch-test",
226→    passed: !hasErrors,
227→    branchResults,
228→    batchFindings,
229→    durationMs: Date.now() - startTime,
230→  };
231→}
